                       </div>
                     </div>
                     <div className="flex flex-col items-end text-right gap-1">
                       <span className={"inline-flex items-center rounded-full border px-2 py-0.5 text-[10px] font-semibold uppercase tracking-wider " + badgeClass(block.status)}>
                         {statusLabel(block.status)}
