           <StatCard title="Highest Fee" label="60m peak" value={liveDashboard.highestFee.toFixed(1)} unit="MON" />
           <StatCard title="Block Time" label="1m avg" value={liveDashboard.blockTime} unit="MS" />
           <StatCard title="Block Fullness" label="60m avg" value={liveDashboard.fullness.toFixed(1)} unit="%" />
           <StatCard title="Largest Block" label="60m peak" value={liveDashboard.largestBlock} unit="TXS" />
           <StatCard title="Total Staked" label="Current" value={stats.totalStake.toLocaleString(undefined, { notation: 'compact' })} unit="MON" />
           <StatCard title="Pending Stake" label="Next Epoch" value={(Number(liveDashboard.pendingStake)/1000000).toFixed(2)} unit="M MON" />
           <StatCard title="APY" label="Current" value={liveDashboard.apy} unit="%" />
        </div>
      </div>
    </div>
  );
}

