'use client';

import { useEffect, useMemo, useRef, useState } from 'react';
import Footer from '@/app/components/Footer';
import Navbar from '@/app/components/Navbar';
import DashboardGrid from '@/app/components/DashboardGrid';

type Validator = {
  id: string;
  name: string;
  description: string;
  imageUrl: string;
  projectUrl: string;
  address: string;
  netAddress: string;
  p2pAddress: string;
  votingPower: number;
  gasPrice: number;
  commissionRate: number;
  stakingPoolIotaBalance: number;
  nextEpochStake: number;
  location: {
    lat: number | null;
    lng: number | null;
    source: string;
    label: string;
    host: string | null;
  };
};

type Payload = {
  updatedAt: string | null;
  total: number;
  refreshMs: number;
  latestCheckpoint: number | null;
  checkpointHistory: number[];
  validators: Validator[];
  error: string | null;
};

type Arc = {
  id: string;
  startId: string;
  endId: string;
  startLat: number;
  startLng: number;
  endLat: number;
  endLng: number;
  color: string;
  status: 'proposal' | 'finalized' | 'timeout';
  stroke?: number;
  altitude?: number;
  dashTime?: number;
};

type GlobeNode = {
  id: string;
  kind: 'node' | 'cluster';
  lat: number;
  lng: number;
  count: number;
  validators: Validator[];
};

type ProgressStatus = 'proposal' | 'finalized' | 'timeout';

type ProgressEntry = {
  state: ProgressStatus;
  checkpoint: number;
};

const ARC_STATUS_COLORS: Record<ProgressStatus, string> = {
  proposal: '#38bdf8',
  finalized: '#a855f7',
  timeout: '#ef4444',
};

const navItems: { label: string; href: string }[] = [
  { label: 'Home', href: '/' },
  { label: 'Validators', href: '/validators' },
  { label: 'Charts', href: '/charts' },
  { label: 'Stacking', href: '/stacking' },
];

function formatCompact(value: number) {
  return new Intl.NumberFormat('en-US', {
    notation: 'compact',
    maximumFractionDigits: 2,
  }).format(value);
}

function formatPercent(value: number) {
  return `${value.toFixed(2)}%`;
}

function formatNumber(value: number) {
  return value.toLocaleString('en-US');
}

function isFiniteCoordinate(value: number | null): value is number {
  return typeof value === 'number' && Number.isFinite(value);
}

function hasCoordinates(validator: Validator) {
  return isFiniteCoordinate(validator.location.lat) && isFiniteCoordinate(validator.location.lng);
}

function formatCoordinate(value: number | null, axis: 'lat' | 'lng') {
  if (!isFiniteCoordinate(value)) {
    return 'N/A';
  }

  const suffix = axis === 'lat' ? (value >= 0 ? 'N' : 'S') : value >= 0 ? 'E' : 'W';
  return `${Math.abs(value).toFixed(4)}°${suffix}`;
}

function formatLocationDetails(location: Validator['location']) {
  const base = location.label || location.source || location.host || 'Unknown location';
  if (!isFiniteCoordinate(location.lat) || !isFiniteCoordinate(location.lng)) {
    return `${base} (coordinates unavailable)`;
  }

  return `${base} (${formatCoordinate(location.lat, 'lat')}, ${formatCoordinate(location.lng, 'lng')})`;
}

function haversineDistanceKm(lat1: number, lng1: number, lat2: number, lng2: number) {
  const toRadians = Math.PI / 180;
  const dLat = (lat2 - lat1) * toRadians;
  const dLng = (lng2 - lng1) * toRadians;
  const rLat1 = lat1 * toRadians;
  const rLat2 = lat2 * toRadians;

  const sinDLat = Math.sin(dLat / 2);
  const sinDLng = Math.sin(dLng / 2);
  const a = sinDLat * sinDLat + Math.cos(rLat1) * Math.cos(rLat2) * sinDLng * sinDLng;
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));

  return 6371 * c;
}

function sphericalCentroid(items: Validator[]) {
  let x = 0;
  let y = 0;
  let z = 0;

  for (const item of items) {
    if (!isFiniteCoordinate(item.location.lat) || !isFiniteCoordinate(item.location.lng)) {
      continue;
    }
    const latRad = (item.location.lat * Math.PI) / 180;
    const lngRad = (item.location.lng * Math.PI) / 180;
    x += Math.cos(latRad) * Math.cos(lngRad);
    y += Math.cos(latRad) * Math.sin(lngRad);
    z += Math.sin(latRad);
  }

  const count = Math.max(1, items.length);
  x /= count;
  y /= count;
  z /= count;

  const lng = (Math.atan2(y, x) * 180) / Math.PI;
  const hyp = Math.sqrt(x * x + y * y);
  const lat = (Math.atan2(z, hyp) * 180) / Math.PI;

  return {
    lat: Number(lat.toFixed(5)),
    lng: Number(lng.toFixed(5)),
  };
}

function getInitials(name: string) {
  const trimmed = name.trim();
  if (!trimmed) {
    return 'N';
  }

  const parts = trimmed.split(/\s+/).slice(0, 2);
  return parts.map((part) => part[0]?.toUpperCase() ?? '').join('');
}

function buildProgressEntries(checkpointHistory: number[]) {
  const entries: ProgressEntry[] = [];
  if (checkpointHistory.length === 0) {
    return entries;
  }

  for (let i = 0; i < checkpointHistory.length; i += 1) {
    const current = checkpointHistory[i];
    const next = checkpointHistory[i + 1];

    if (typeof next !== 'number') {
      // Newest checkpoint stays in proposal state until the next event arrives.
      entries.push({
        state: 'proposal',
        checkpoint: current,
      });
      continue;
    }

    const delta = next - current;
    entries.push({
      state: delta > 0 ? 'finalized' : 'timeout',
      checkpoint: current,
    });
  }

  return entries;
}

function buildArcs(nodes: GlobeNode[], resultStatuses: Array<'finalized' | 'timeout'>) {
  if (nodes.length < 2) {
    return [] as Arc[];
  }

  const statusStream: Array<'finalized' | 'timeout'> = resultStatuses.length > 0 ? resultStatuses : ['finalized'];
  const ordered = [...nodes].sort((a, b) => a.lng - b.lng || a.lat - b.lat || a.id.localeCompare(b.id));
  const pairCount = Math.min(6, ordered.length - 1);
  const arcs: Arc[] = [];

  for (let i = 0; i < pairCount; i += 1) {
    const from = ordered[i];
    const to = ordered[i + 1];
    if (!from || !to) {
      continue;
    }

    arcs.push({
      id: `${from.id}->${to.id}:proposal:${i}`,
      startId: from.id,
      endId: to.id,
      startLat: from.lat,
      startLng: from.lng,
      endLat: to.lat,
      endLng: to.lng,
      status: 'proposal',
      color: ARC_STATUS_COLORS.proposal,
    });

    const status = statusStream[i % statusStream.length];
    arcs.push({
      id: `${to.id}->${from.id}:${status}:${i}`,
      startId: to.id,
      endId: from.id,
      startLat: to.lat,
      startLng: to.lng,
      endLat: from.lat,
      endLng: from.lng,
      status,
      color: ARC_STATUS_COLORS[status],
    });
  }

  return arcs;
}

function buildGlobeNodes(validators: Validator[]) {
  const geolocated = validators
    .filter(hasCoordinates)
    .sort(
      (a, b) =>
        (a.location.lng as number) - (b.location.lng as number) ||
        (a.location.lat as number) - (b.location.lat as number) ||
        a.id.localeCompare(b.id),
    );
  if (geolocated.length === 0) {
    return [] as GlobeNode[];
  }

  const clusterWithRadius = (clusterRadiusKm: number) => {
    const clusters: Array<{ validators: Validator[]; lat: number; lng: number }> = [];

    for (const validator of geolocated) {
      const lat = validator.location.lat as number;
      const lng = validator.location.lng as number;

      let bestIndex = -1;
      let bestDistance = Number.POSITIVE_INFINITY;

      for (let i = 0; i < clusters.length; i += 1) {
        const cluster = clusters[i];
        const distance = haversineDistanceKm(lat, lng, cluster.lat, cluster.lng);
        if (distance <= clusterRadiusKm && distance < bestDistance) {
          bestDistance = distance;
          bestIndex = i;
        }
      }

      if (bestIndex === -1) {
        clusters.push({ validators: [validator], lat, lng });
        continue;
      }

      const target = clusters[bestIndex];
      target.validators.push(validator);
      const centroid = sphericalCentroid(target.validators);
      target.lat = centroid.lat;
      target.lng = centroid.lng;
    }

    return clusters;
  };

  const radiusCandidatesKm = [280, 420, 620];
  let clusters = clusterWithRadius(radiusCandidatesKm[0]);
  for (let i = 1; i < radiusCandidatesKm.length; i += 1) {
    const hasCluster = clusters.some((cluster) => cluster.validators.length > 1);
    if (hasCluster) {
      break;
    }
    clusters = clusterWithRadius(radiusCandidatesKm[i]);
  }

  return clusters.map((cluster) => {
    const members = [...cluster.validators].sort((a, b) => b.votingPower - a.votingPower);
    const topValidator = members[0];
    const isCluster = members.length > 1;
    const centroid = sphericalCentroid(members);
    const anchor = members
      .slice()
      .sort((a, b) => {
        const aDistance = haversineDistanceKm(
          centroid.lat,
          centroid.lng,
          (a.location.lat as number) ?? centroid.lat,
          (a.location.lng as number) ?? centroid.lng,
        );
        const bDistance = haversineDistanceKm(
          centroid.lat,
          centroid.lng,
          (b.location.lat as number) ?? centroid.lat,
          (b.location.lng as number) ?? centroid.lng,
        );
        return aDistance - bDistance || a.id.localeCompare(b.id);
      })[0] ?? topValidator;
    const anchorLat = (anchor.location.lat as number) ?? centroid.lat;
    const anchorLng = (anchor.location.lng as number) ?? centroid.lng;

    return {
      id: isCluster ? members.map((item) => item.id).sort().join('|') : topValidator.id,
      kind: (isCluster ? 'cluster' : 'node') as GlobeNode['kind'],
      lat: Number(anchorLat.toFixed(5)),
      lng: Number(anchorLng.toFixed(5)),
      count: members.length,
      validators: members,
    };
  });
}

function buildRecentBlocks(
  validators: Validator[],
  latestCheckpoint: number | null,
  checkpointHistory: number[],
  progressEntries: ProgressEntry[],
) {
  if (validators.length === 0) {
    return [] as Array<{
      validator: string;
      validatorId: string;
      imageUrl: string;
      status: ProgressStatus;
      block: number;
      round: number;
      transactions: number;
    }>;
  }

  const uniqueHistory = [...new Set(checkpointHistory)].filter((value) => Number.isFinite(value));
  const recentCheckpoints = uniqueHistory.slice(-2).reverse();

  if (Number.isFinite(latestCheckpoint) && !recentCheckpoints.includes(latestCheckpoint as number)) {
    recentCheckpoints.unshift(latestCheckpoint as number);
  }

  const checkpoints = recentCheckpoints.slice(0, 2);
  const fallbackCheckpoint = Number.isFinite(latestCheckpoint) ? (latestCheckpoint as number) : 0;
  const totalVotingPower = validators.reduce((sum, validator) => sum + validator.votingPower, 0);

  const statusByCheckpoint = new Map<number, ProgressStatus>();
  for (const entry of progressEntries) {
    if (entry.state === 'proposal') {
      continue;
    }
    statusByCheckpoint.set(entry.checkpoint, entry.state);
  }

  return checkpoints.map((checkpoint, index) => {
    const validator = validators[Math.abs(checkpoint) % validators.length] ?? validators[index % validators.length];
    const block = Math.max(1, checkpoint || fallbackCheckpoint || index + 1);
    const round = block * 2;
    const status = statusByCheckpoint.get(checkpoint) ?? 'proposal';
    const votingShare = totalVotingPower > 0 ? validator.votingPower / totalVotingPower : 0;
    const statusFactor = status === 'finalized' ? 1 : status === 'proposal' ? 0.7 : 0.35;
    const transactions = Math.max(1, Math.round(votingShare * 12000 * statusFactor));

    return {
      validator: validator.name,
      validatorId: validator.id,
      imageUrl: validator.imageUrl,
      status,
      block,
      round,
      transactions,
    };
  });
}

export default function Page() {
  const globeRef = useRef<HTMLDivElement | null>(null);
  const globeApiRef = useRef<any>(null);
  const [payload, setPayload] = useState<Payload>({
    updatedAt: null,
    total: 0,
    refreshMs: 8000,
    latestCheckpoint: null,
    checkpointHistory: [],
    validators: [],
    error: null,
  });
  const [isLive, setIsLive] = useState(false);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [selectedNodeData, setSelectedNodeData] = useState<GlobeNode | null>(null);
  const [hoverData, setHoverData] = useState<{ node: GlobeNode; x: number; y: number } | null>(null);
  const [activeNodeId, setActiveNodeId] = useState<string | null>(null);
  const [query, setQuery] = useState('');

  const sorted = useMemo(() => {
    return [...payload.validators].sort((a, b) => b.votingPower - a.votingPower);
  }, [payload.validators]);

  const filtered = useMemo(() => {
    const normalized = query.trim().toLowerCase();
    if (!normalized) {
      return sorted;
    }

    return sorted.filter((validator) => {
      return (
        validator.name.toLowerCase().includes(normalized) ||
        validator.address.toLowerCase().includes(normalized)
      );
    });
  }, [query, sorted]);

  const selected = useMemo(() => {
    if (!selectedId) {
      return sorted[0] ?? null;
    }
    return sorted.find((validator) => validator.id === selectedId) ?? sorted[0] ?? null;
  }, [selectedId, sorted]);

  const selectedCardValidators = useMemo(() => {
    if (!selectedNodeData) {
      return [] as Validator[];
    }

    return [...selectedNodeData.validators].sort((a, b) => b.votingPower - a.votingPower);
  }, [selectedNodeData]);

  const stats = useMemo(() => {
    const totalStake = sorted.reduce((acc, item) => acc + item.stakingPoolIotaBalance, 0);
    const avgCommission = sorted.length
      ? sorted.reduce((acc, item) => acc + item.commissionRate, 0) / sorted.length
      : 0;
    const totalVotingPower = sorted.reduce((acc, item) => acc + item.votingPower, 0);

    return { totalStake, avgCommission, totalVotingPower };
  }, [sorted]);

  const liveDashboard = useMemo(() => {
    const historyWindow = payload.checkpointHistory.slice(-60);
    const progressEntries = buildProgressEntries(historyWindow);
    const proposalCount = progressEntries.filter((entry) => entry.state === 'proposal').length;
    const proposalFinalized = progressEntries.filter((entry) => entry.state === 'finalized').length;
    const proposalTimeout = progressEntries.filter((entry) => entry.state === 'timeout').length;
    const progressWindow = Math.max(1, progressEntries.length);
    const proposalSuccess = proposalFinalized + proposalTimeout > 0
      ? (proposalFinalized / (proposalFinalized + proposalTimeout)) * 100
      : 0;

    const medianFee = sorted.length > 0
      ? sorted[Math.floor(sorted.length / 2)].gasPrice / 100000
      : 0;
    const highestFee = sorted.length > 0
      ? Math.max(...sorted.map((validator) => validator.gasPrice)) / 1000
      : 0;

    const tps = Math.max(1, Math.round(stats.totalVotingPower / 1200));
    const peakTps = Math.max(tps, Math.round(stats.totalVotingPower / 30));
    const blockTime = Math.max(220, 550 - Math.round(stats.avgCommission * 10));
    const fullness = Math.min(99, Math.max(0.2, stats.avgCommission / 12));

    const recentBlocks = buildRecentBlocks(sorted, payload.latestCheckpoint, historyWindow, progressEntries);

    return {
      proposalCount,
      proposalFinalized,
      proposalTimeout,
      progressWindow,
      progressEntries,
      proposalSuccess,
      latestCheckpoint: payload.latestCheckpoint,
      tps,
      peakTps,
      medianFee,
      highestFee,
      blockTime,
      fullness,
      largestBlock: recentBlocks.reduce((max, block) => Math.max(max, block.transactions), 1),
      pendingStake: ((payload.latestCheckpoint ?? 0) * Math.max(1, stats.avgCommission) * 1000).toFixed(2),
      apy: Math.max(4.2, (12 - stats.avgCommission / 2)).toFixed(2),
      recentBlocks,
    };
  }, [sorted, stats.avgCommission, stats.totalVotingPower, payload.latestCheckpoint, payload.checkpointHistory]);

  const globeNodes = useMemo(() => buildGlobeNodes(sorted), [sorted]);

  const baseArcs = useMemo(() => {
    const resultStatuses = liveDashboard.progressEntries
      .map((entry: ProgressEntry) => entry.state)
      .filter((state: ProgressStatus): state is 'finalized' | 'timeout' => state === 'finalized' || state === 'timeout');
    const base = buildArcs(globeNodes, resultStatuses);
    if (base.length === 0) {
      return base;
    }

    const refreshMs = Math.max(3500, payload.refreshMs || 8000);
    return base.map((arc) => {
      const rgb = arc.status === 'proposal'
        ? '56, 189, 248'
        : arc.status === 'finalized'
          ? '168, 85, 247'
          : '239, 68, 68';
      return {
        ...arc,
        color: `rgba(${rgb}, 0.72)`,
        stroke: arc.status === 'proposal' ? 0.2 : 0.16,
        altitude: 0.055,
        dashTime: Math.max(2800, Math.floor(refreshMs * 1.15)),
      };
    });
  }, [globeNodes, liveDashboard.progressEntries, payload.refreshMs]);

  const arcs = useMemo(() => {
    const focusNodeId = activeNodeId ?? selectedNodeData?.id ?? null;
    if (!focusNodeId) {
      return baseArcs;
    }

    return baseArcs.map((arc) => {
      const isConnected = arc.startId === focusNodeId || arc.endId === focusNodeId;
      if (isConnected) {
        return {
          ...arc,
          color: arc.color.replace(/0\.72\)/, '0.95)'),
          stroke: (arc.stroke ?? 0.2) + 0.07,
          altitude: (arc.altitude ?? 0.055) + 0.02,
          dashTime: Math.max(2200, (arc.dashTime ?? 3000) - 550),
        };
      }

      return {
        ...arc,
        color: arc.color.replace(/0\.72\)/, '0.2)'),
      };
    });
  }, [baseArcs, activeNodeId, selectedNodeData?.id]);

  useEffect(() => {
    const source = new EventSource('/api/validators/stream');
    let retryHandle: number | undefined;

    source.onopen = () => setIsLive(true);
    source.onmessage = (event) => {
      const data = JSON.parse(event.data) as Payload;
      setPayload(data);
      setIsLive(true);
    };
    source.onerror = () => {
      setIsLive(false);
      source.close();
      retryHandle = window.setTimeout(async () => {
        const response = await fetch('/api/validators', { cache: 'no-store' });
        if (!response.ok) {
          return;
        }
        const data = (await response.json()) as Payload;
        setPayload(data);
      }, 2500);
    };

    return () => {
      source.close();
      if (retryHandle) {
        clearTimeout(retryHandle);
      }
    };
  }, []);

  useEffect(() => {
    let destroyed = false;

    async function init() {
      if (!globeRef.current || globeApiRef.current) {
        return;
      }

      const module = await import('globe.gl');
      if (destroyed || !globeRef.current) {
        return;
      }

      const GlobeFactory = module.default as any;
      const globe = GlobeFactory()(globeRef.current)
        .backgroundColor('rgba(0,0,0,0)')
        .globeImageUrl('/globe/earth-map.svg')
        .bumpImageUrl('/globe/earth-topology.png')
        .backgroundImageUrl('/globe/night-sky.png')
        .showAtmosphere(true)
        .atmosphereColor('#8f8ca8')
        .atmosphereAltitude(0.1)
        .arcColor((a: Arc) => a.color)
        .arcAltitude((a: Arc) => a.altitude ?? 0.12)
        .arcStroke((a: Arc) => a.stroke ?? 0.34)
        .arcDashLength((a: Arc) => (a.status === 'proposal' ? 0.28 : 0.2))
        .arcDashGap((a: Arc) => (a.status === 'proposal' ? 0.82 : 1.1))
        .arcDashInitialGap((a: Arc) => {
          let hash = 0;
          for (let i = 0; i < a.id.length; i += 1) {
            hash = (hash * 31 + a.id.charCodeAt(i)) | 0;
          }
          return Math.abs(hash % 180) / 100;
        })
        .arcDashAnimateTime((a: Arc) => a.dashTime ?? 2000)
        .htmlLat((d: GlobeNode) => d.lat)
        .htmlLng((d: GlobeNode) => d.lng)
        .htmlAltitude((d: GlobeNode) => (d.kind === 'cluster' ? 0.007 : 0.003))
        .htmlElement((d: GlobeNode) => {
          const el = document.createElement('button');
          el.type = 'button';
          el.className = d.kind === 'cluster' ? 'marker-cluster marker-interactive' : 'marker-node marker-interactive';
          el.setAttribute('aria-label', d.kind === 'cluster' ? `Cluster with ${d.count} validators` : d.validators[0]?.name ?? 'Validator node');
          el.style.pointerEvents = 'auto';
          el.style.touchAction = 'manipulation';

          if (d.kind === 'cluster') {
            el.textContent = String(d.count);
          }

          el.onpointerdown = (event) => {
            event.stopPropagation();
          };

          el.onpointerenter = (e) => {
            setActiveNodeId(d.id);
            setHoverData({ node: d, x: e.clientX, y: e.clientY });
          };
          el.onpointermove = (e) => {
            setHoverData({ node: d, x: e.clientX, y: e.clientY });
          };
          el.onpointerleave = () => {
            setActiveNodeId((prev) => (prev === d.id ? null : prev));
            setHoverData(null);
          };

          el.onclick = (event) => {
            event.preventDefault();
            event.stopPropagation();
            setSelectedNodeData(d);
            setActiveNodeId(d.id);
            const target = d.validators[0];
            if (!target) {
              return;
            }
            setSelectedId(target.id);
            globe.pointOfView({ lat: d.lat, lng: d.lng, altitude: 1.65 }, 900);
          };

          return el;
        });

      const globeMaterial = globe.globeMaterial?.();
      if (globeMaterial) {
        globeMaterial.color.set('#8e8f9b');
        globeMaterial.emissive.set('#2b233e');
        globeMaterial.emissiveIntensity = 0.26;
        globeMaterial.shininess = 0.25;
      }

      const controls = globe.controls?.();
      if (controls) {
        controls.autoRotate = true;
        controls.autoRotateSpeed = 0.42;
        controls.minDistance = 110;
        controls.maxDistance = 480;
      }

      const resize = () => {
        if (!globeRef.current || !globeApiRef.current) {
          return;
        }
        const { width, height } = globeRef.current.getBoundingClientRect();
        globeApiRef.current.width(width);
        globeApiRef.current.height(height);
      };

      window.addEventListener('resize', resize);
      resize();

      globeApiRef.current = globe;

      return () => {
        window.removeEventListener('resize', resize);
      };
    }

    const cleanupPromise = init();

    return () => {
      destroyed = true;
      Promise.resolve(cleanupPromise).then((cleanupFn) => {
        if (typeof cleanupFn === 'function') {
          cleanupFn();
        }
      });
      if (globeRef.current) {
        globeRef.current.innerHTML = '';
      }
      globeApiRef.current = null;
    };
  }, []);

  useEffect(() => {
    if (!globeApiRef.current) {
      return;
    }

    globeApiRef.current.htmlElementsData(globeNodes);
    globeApiRef.current.arcsData(arcs);
  }, [globeNodes, arcs]);

  useEffect(() => {
    if (!selectedNodeData) {
      return;
    }

    const syncedNode = globeNodes.find((node) => node.id === selectedNodeData.id);
    if (syncedNode) {
      setSelectedNodeData(syncedNode);
      return;
    }

    setSelectedNodeData(null);
  }, [globeNodes, selectedNodeData]);

  useEffect(() => {
    if (selectedNodeData) {
      setActiveNodeId(selectedNodeData.id);
      return;
    }
    setActiveNodeId(null);
  }, [selectedNodeData]);

  return (
    <main className="min-h-screen overflow-x-clip text-blue-50">
      <div className="w-full z-[100] relative">
        <Navbar items={navItems} activeHref="/" isLive={isLive} />
      </div>

      <section className="glass-panel animate-fade-in-up relative flex w-full flex-col overflow-hidden rounded-none border-x-0 border-t-0 p-0 shadow-2xl h-[65vh] min-h-[500px] md:min-h-[600px] lg:min-h-[720px]">
        <div className="relative flex-grow w-full">
          <div className="scanline z-20" />
          <div ref={globeRef} className="absolute inset-0 z-10 w-full h-full [&>div]:!h-full [&>div]:!w-full [&_canvas]:!h-full [&_canvas]:!w-full" />
        </div>

        {selectedNodeData && (
          <div className="absolute top-4 right-4 z-[60] w-[min(92vw,420px)] glass-panel border border-purple-500/30 bg-black/50 p-3 backdrop-blur-xl">
            <div className="mb-2 flex items-start justify-between gap-3">
              <div>
                <p className="text-[10px] uppercase tracking-[0.18em] text-purple-300">
                  {selectedNodeData.kind === 'cluster' ? 'Cluster Details' : 'Node Details'}
                </p>
                <h3 className="font-title text-sm text-white md:text-base">
                  {selectedNodeData.kind === 'cluster'
                    ? `${selectedNodeData.count} nodes in selected cluster`
                    : selectedNodeData.validators[0]?.name ?? 'Selected node'}
                </h3>
              </div>
              <button
                type="button"
                onClick={() => setSelectedNodeData(null)}
                className="rounded-md border border-zinc-700 bg-zinc-900/90 px-2 py-1 text-[10px] uppercase tracking-wider text-zinc-300 transition hover:border-purple-300 hover:text-white"
              >
                Close
              </button>
            </div>

            <div className="max-h-[280px] space-y-2 overflow-y-auto pr-1">
              {selectedCardValidators.map((validator) => {
                const imageUrl = validator.imageUrl?.trim();
                return (
                  <article
                    key={validator.id}
                    className="flex items-center gap-3 rounded-xl border border-white/10 bg-zinc-950/70 p-2"
                  >
                    <div className="relative grid h-11 w-11 shrink-0 place-items-center overflow-hidden rounded-lg border border-white/15 bg-gradient-to-br from-purple-600/60 to-blue-600/60 text-xs font-bold text-white">
                      <span>{getInitials(validator.name)}</span>
                      {imageUrl ? (
                        <img
                          src={imageUrl}
                          alt={validator.name}
                          className="absolute inset-0 h-full w-full object-cover"
                          loading="lazy"
                          onError={(event) => {
                            event.currentTarget.style.display = 'none';
                          }}
                        />
                      ) : null}
                    </div>
                    <div className="min-w-0 flex-1">
                      <p className="truncate text-sm font-semibold text-white">{validator.name}</p>
                      <p className="truncate text-xs text-zinc-400">
                        {formatLocationDetails(validator.location)}
                      </p>
                    </div>
                    <p className="shrink-0 text-[11px] font-medium text-purple-200">
                      {formatCompact(validator.votingPower)} VP
                    </p>
                  </article>
                );
              })}
            </div>
          </div>
        )}

        {/* Desktop Info Panel Left */}
          {selected && (
             <div className="absolute bottom-6 left-6 z-50 hidden lg:block glass-panel animate-fade-in-up p-4 border border-purple-500/30 bg-black/40 backdrop-blur-xl">
               <div className="flex flex-col gap-1.5 text-white">
                  <div className="text-[10px] text-purple-400 uppercase tracking-widest font-semibold flex items-center gap-2">
                    <span className="w-1.5 h-1.5 rounded-full bg-purple-500 animate-pulse" />
                    Selected Node
                  </div>
                  <div className="font-semibold text-lg">{selected.name}</div>
                  <div className="text-xs text-zinc-400 flex items-center gap-2">
                    <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                    {formatLocationDetails(selected.location)}
                  </div>
               </div>
             </div>
          )}

          {/* Desktop Info Panel Right */}
          <div className="absolute bottom-6 right-6 z-50 hidden lg:block glass-panel animate-fade-in-up p-4 border border-purple-500/30 bg-black/40 backdrop-blur-xl">
            <div className="flex items-center justify-between gap-8 text-white min-w-[240px]">
               <div className="flex flex-col gap-1">
                 <span className="text-[10px] uppercase text-zinc-500 tracking-widest font-semibold">Active Validators</span>
                 <span className="text-xl font-medium text-white">{payload.total}</span>
               </div>
               <div className="flex flex-col gap-1 text-right">
                 <span className="text-[10px] uppercase text-zinc-500 tracking-widest font-semibold">Total Voting Power</span>
                 <span className="text-xl font-medium text-purple-100">{formatCompact(stats.totalVotingPower)}</span>
               </div>
            </div>
          </div>
        </section>

      <div className="mx-auto flex w-full max-w-[1200px] flex-col gap-6 px-4 py-4 md:px-8 md:py-8 mt-2 md:mt-4">
        <DashboardGrid payload={payload} stats={stats} liveDashboard={liveDashboard} />

        <Footer />
      </div>

      {/* Hover Tooltip Overlay */}
      {hoverData && (
        <div
          className="fixed z-[9999] pointer-events-none flex flex-col gap-1 glass-panel animate-fade-in-up p-3 w-max max-w-[280px] bg-black/60 shadow-2xl border border-purple-500/30"
          style={{
            left: Math.min(hoverData.x + 15, typeof window !== 'undefined' ? window.innerWidth - 250 : hoverData.x),
            top: hoverData.y + 15,
          }}
        >
          {hoverData.node.kind === 'cluster' ? (
            <>
              <div className="text-[10px] text-purple-400 uppercase tracking-widest mb-1.5 font-bold flex items-center gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-purple-500" />
                {hoverData.node.count} Validators
              </div>
              <div className="flex flex-col gap-2 max-h-[160px] overflow-hidden">
                {hoverData.node.validators.slice(0, 5).map((v) => (
                  <div key={v.id} className="flex justify-between items-center text-xs gap-4">
                    <div className="flex items-center gap-2 min-w-0">
                      <div className="relative grid h-6 w-6 shrink-0 place-items-center overflow-hidden rounded-md border border-white/15 bg-gradient-to-br from-purple-600/60 to-blue-600/60 text-[9px] font-bold text-white">
                        <span>{getInitials(v.name)}</span>
                        {v.imageUrl ? (
                          <img
                            src={v.imageUrl}
                            alt={v.name}
                            className="absolute inset-0 h-full w-full object-cover"
                            loading="lazy"
                            onError={(event) => {
                              event.currentTarget.style.display = 'none';
                            }}
                          />
                        ) : null}
                      </div>
                      <span className="text-white truncate max-w-[130px] font-medium">{v.name}</span>
                    </div>
                    <span className="text-zinc-400 whitespace-nowrap font-mono">{formatCompact(v.votingPower)} VP</span>
                  </div>
                ))}
                {hoverData.node.validators.length > 5 && (
                  <div className="text-[10px] text-purple-300 mt-1 italic opacity-80">
                    + {hoverData.node.validators.length - 5} more...
                  </div>
                )}
              </div>
            </>
          ) : (
            <>
              <div className="text-[10px] text-purple-400 uppercase tracking-widest mb-1.5 font-bold flex items-center gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-purple-500 animate-pulse" />
                Live Node
              </div>
              <div className="flex items-center gap-2">
                <div className="relative grid h-8 w-8 shrink-0 place-items-center overflow-hidden rounded-md border border-white/15 bg-gradient-to-br from-purple-600/60 to-blue-600/60 text-[10px] font-bold text-white">
                  <span>{getInitials(hoverData.node.validators[0]?.name ?? '')}</span>
                  {hoverData.node.validators[0]?.imageUrl ? (
                    <img
                      src={hoverData.node.validators[0].imageUrl}
                      alt={hoverData.node.validators[0]?.name ?? 'Validator'}
                      className="absolute inset-0 h-full w-full object-cover"
                      loading="lazy"
                      onError={(event) => {
                        event.currentTarget.style.display = 'none';
                      }}
                    />
                  ) : null}
                </div>
                <div className="font-semibold text-base text-white truncate max-w-[190px]">{hoverData.node.validators[0]?.name}</div>
              </div>
              <div className="text-xs text-zinc-400 mt-0.5">
                {hoverData.node.validators[0] ? formatLocationDetails(hoverData.node.validators[0].location) : 'Unknown location'}
              </div>
              <div className="text-xs text-zinc-300 mt-2 pt-2 border-t border-white/10 flex justify-between items-center">
                <span>Power:</span>
                <span className="font-medium text-white font-mono">{formatCompact(hoverData.node.validators[0]?.votingPower ?? 0)}</span>
              </div>
            </>
          )}
        </div>
      )}
    </main>
  );
}

import { z } from 'zod';
import dns from 'node:dns/promises';
import { isIP } from 'node:net';

const envSchema = z.object({
  IOTA_RPC_URL: z.string().url().default('https://api.mainnet.iota.cafe'),
  IOTA_RPC_METHOD: z.string().default('iotax_getLatestIotaSystemState'),
  IOTA_CHECKPOINT_METHOD: z.string().default('iota_getLatestCheckpointSequenceNumber'),
  IOTA_RPC_AUTH_HEADER: z.string().optional(),
  IOTA_RPC_AUTH_TOKEN: z.string().optional(),
  CHECKPOINT_HISTORY_SIZE: z.coerce.number().int().min(10).max(240).default(60),
  VALIDATORS_REFRESH_MS: z.coerce.number().int().min(5000).default(8000),
});

const env = envSchema.parse(process.env);

type RawValidator = {
  iotaAddress: string;
  name: string;
  description: string;
  imageUrl: string;
  projectUrl: string;
  netAddress: string;
  p2pAddress: string;
  votingPower: string;
  gasPrice: string;
  commissionRate: string;
  stakingPoolIotaBalance: string;
  nextEpochStake: string;
};

export type Validator = {
  id: string;
  name: string;
  description: string;
  imageUrl: string;
  projectUrl: string;
  address: string;
  netAddress: string;
  p2pAddress: string;
  votingPower: number;
  gasPrice: number;
  commissionRate: number;
  stakingPoolIotaBalance: number;
  nextEpochStake: number;
  location: {
    lat: number | null;
    lng: number | null;
    source: string;
    label: string;
    host: string | null;
  };
};

export type ValidatorsPayload = {
  updatedAt: string | null;
  total: number;
  refreshMs: number;
  latestCheckpoint: number | null;
  checkpointHistory: number[];
  validators: Validator[];
  error: string | null;
};

const state: ValidatorsPayload = {
  updatedAt: null,
  total: 0,
  refreshMs: env.VALIDATORS_REFRESH_MS,
  latestCheckpoint: null,
  checkpointHistory: [],
  validators: [],
  error: null,
};

type GeoPoint = {
  lat: number | null;
  lng: number | null;
  source: string;
  label: string;
};

type GeoCacheEntry = {
  point: GeoPoint;
  expiresAt: number;
};

const GEO_SUCCESS_TTL_MS = 24 * 60 * 60 * 1000;
const GEO_FALLBACK_TTL_MS = 15 * 60 * 1000;

const geoCache = new Map<string, GeoCacheEntry>();
let refreshPromise: Promise<ValidatorsPayload> | null = null;
let lastRefreshMs = 0;

function hashToUnit(value: string) {
  let hash = 0;
  for (let i = 0; i < value.length; i += 1) {
    hash = (hash << 5) - hash + value.charCodeAt(i);
    hash |= 0;
  }
  return (Math.abs(hash) % 1000000) / 1000000;
}

function approximateCoordinates(seed: string) {
  const lat = -58 + hashToUnit(`${seed}-lat`) * 132;
  const lng = -180 + hashToUnit(`${seed}-lng`) * 360;
  return {
    lat: Number(lat.toFixed(5)),
    lng: Number(lng.toFixed(5)),
    source: 'approximate',
    label: 'Approximate location (fallback)',
  };
}

function unresolvedLocation(reason: string, host: string | null) {
  const hostLabel = host ? ` for ${host}` : '';
  return {
    lat: null,
    lng: null,
    source: 'unresolved',
    label: `Location unavailable (${reason}${hostLabel})`,
  };
}

function getCachedGeo(hostname: string) {
  const cached = geoCache.get(hostname);
  if (!cached) {
    return null;
  }

  if (cached.expiresAt < Date.now()) {
    geoCache.delete(hostname);
    return null;
  }

  return cached.point;
}

function setCachedGeo(hostname: string, point: GeoPoint, ttlMs: number) {
  geoCache.set(hostname, {
    point,
    expiresAt: Date.now() + ttlMs,
  });
}

function parseMultiaddrHost(address = '') {
  const value = String(address);
  const match = value.match(/\/(dns|dns4|dns6|ip4|ip6)\/([^/]+)/i);
  if (!match) {
    return null;
  }

  const protocol = match[1].toLowerCase();
  const host = match[2]?.trim();
  if (!host) {
    return null;
  }

  return {
    host,
    protocol,
  };
}

function parseUrlHost(url = '') {
  const value = String(url).trim();
  if (!value) {
    return null;
  }

  try {
    const parsed = new URL(value);
    return parsed.hostname?.trim() || null;
  } catch {
    return null;
  }
}

function formatLocationSource(body: any) {
  const city = typeof body?.city === 'string' ? body.city.trim() : '';
  const region = typeof body?.region === 'string' ? body.region.trim() : '';
  const country = typeof body?.country === 'string' ? body.country.trim() : '';

  if (city && country) {
    return `${city}, ${country}`;
  }
  if (region && country) {
    return `${region}, ${country}`;
  }
  if (country) {
    return country;
  }

  return 'ipwho.is';
}

function formatLocationLabel(city: string, region: string, country: string, fallback: string) {
  if (city && region && country) {
    return `${city}, ${region}, ${country}`;
  }
  if (city && country) {
    return `${city}, ${country}`;
  }
  if (region && country) {
    return `${region}, ${country}`;
  }
  if (country) {
    return country;
  }
  return fallback;
}

function normalizeGeoFromIpWho(body: any): GeoPoint | null {
  if (!body?.success || typeof body?.latitude !== 'number' || typeof body?.longitude !== 'number') {
    return null;
  }

  const city = typeof body?.city === 'string' ? body.city.trim() : '';
  const region = typeof body?.region === 'string' ? body.region.trim() : '';
  const country = typeof body?.country === 'string' ? body.country.trim() : '';
  return {
    lat: Number(body.latitude.toFixed(5)),
    lng: Number(body.longitude.toFixed(5)),
    source: 'ipwho.is',
    label: formatLocationLabel(city, region, country, formatLocationSource(body)),
  };
}

function normalizeGeoFromFreeIpApi(body: any): GeoPoint | null {
  if (typeof body?.latitude !== 'number' || typeof body?.longitude !== 'number') {
    return null;
  }

  const city = typeof body?.cityName === 'string' ? body.cityName.trim() : '';
  const region = typeof body?.regionName === 'string' ? body.regionName.trim() : '';
  const country = typeof body?.countryName === 'string' ? body.countryName.trim() : '';
  return {
    lat: Number(body.latitude.toFixed(5)),
    lng: Number(body.longitude.toFixed(5)),
    source: 'freeipapi.com',
    label: formatLocationLabel(city, region, country, 'freeipapi.com'),
  };
}

function normalizeGeoFromIpInfo(body: any): GeoPoint | null {
  const loc = typeof body?.loc === 'string' ? body.loc.trim() : '';
  if (!loc.includes(',')) {
    return null;
  }

  const [latRaw, lngRaw] = loc.split(',');
  const lat = Number(latRaw);
  const lng = Number(lngRaw);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) {
    return null;
  }

  const city = typeof body?.city === 'string' ? body.city.trim() : '';
  const region = typeof body?.region === 'string' ? body.region.trim() : '';
  const country = typeof body?.country === 'string' ? body.country.trim() : '';
  return {
    lat: Number(lat.toFixed(5)),
    lng: Number(lng.toFixed(5)),
    source: 'ipinfo.io',
    label: formatLocationLabel(city, region, country, 'ipinfo.io'),
  };
}

async function fetchGeoPoint(target: string): Promise<GeoPoint | null> {
  try {
    const response = await fetch(`https://freeipapi.com/api/json/${encodeURIComponent(target)}`, {
      headers: { Accept: 'application/json' },
      signal: AbortSignal.timeout(6000),
      cache: 'no-store',
    });

    if (response.ok) {
      const body = await response.json();
      const normalized = normalizeGeoFromFreeIpApi(body);
      if (normalized) {
        return normalized;
      }
    }
  } catch {
    // Ignore provider error and continue with another source.
  }

  try {
    const response = await fetch(`https://ipinfo.io/${encodeURIComponent(target)}/json`, {
      headers: { Accept: 'application/json' },
      signal: AbortSignal.timeout(6000),
      cache: 'no-store',
    });

    if (!response.ok) {
      return null;
    }

    const body = await response.json();
    return normalizeGeoFromIpInfo(body);
  } catch {
    // Legacy fallback for environments where newer providers are filtered.
  }

  try {
    const response = await fetch(`https://ipwho.is/${encodeURIComponent(target)}`, {
      headers: { Accept: 'application/json' },
      signal: AbortSignal.timeout(4000),
      cache: 'no-store',
    });

    if (!response.ok) {
      return null;
    }

    const body = await response.json();
    return normalizeGeoFromIpWho(body);
  } catch {
    return null;
  }
}

async function resolveHostForGeo(hostname: string): Promise<string> {
  if (isIP(hostname)) {
    return hostname;
  }

  try {
    const ipv4 = await dns.lookup(hostname, { family: 4, all: false, verbatim: false });
    if (ipv4?.address) {
      return ipv4.address;
    }
  } catch {
    // Ignore and try generic lookup.
  }

  try {
    const result = await dns.lookup(hostname, { all: false, verbatim: false });
    if (result?.address) {
      return result.address;
    }
  } catch {
    // If DNS lookup fails, providers may still handle a DNS host directly.
  }

  return hostname;
}

async function geolocateHost(hostname: string | null, seed: string) {
  if (!hostname) {
    return approximateCoordinates(seed);
  }

  const cached = getCachedGeo(hostname);
  if (cached) {
    return cached;
  }

  const unresolved = unresolvedLocation('provider failure', hostname);
  const approximate = approximateCoordinates(`${hostname}:${seed}`);
  try {
    const geoTarget = await resolveHostForGeo(hostname);
    const point = await fetchGeoPoint(geoTarget);
    if (!point) {
      setCachedGeo(hostname, approximate, GEO_FALLBACK_TTL_MS);
      return {
        ...approximate,
        label: `${approximate.label} (${unresolved.label})`,
      };
    }

    setCachedGeo(hostname, point, GEO_SUCCESS_TTL_MS);
    return point;
  } catch {
    setCachedGeo(hostname, approximate, GEO_FALLBACK_TTL_MS);
    return {
      ...approximate,
      label: `${approximate.label} (${unresolved.label})`,
    };
  }
}

async function geolocateFromHosts(hosts: Array<string | null>, seed: string) {
  const uniqueHosts = [...new Set(hosts.map((host) => (host || '').trim()).filter(Boolean))];
  for (const host of uniqueHosts) {
    const point = await geolocateHost(host, seed);
    if (point.source !== 'approximate') {
      return {
        point,
        host,
      };
    }
  }

  const fallbackHost = uniqueHosts[0] ?? null;
  const point = await geolocateHost(fallbackHost, seed);
  return {
    point,
    host: fallbackHost,
  };
}

function normalize(raw: RawValidator): Omit<Validator, 'location'> {
  return {
    id: raw.iotaAddress,
    name: raw.name,
    description: raw.description,
    imageUrl: raw.imageUrl,
    projectUrl: raw.projectUrl,
    address: raw.iotaAddress,
    netAddress: raw.netAddress,
    p2pAddress: raw.p2pAddress,
    votingPower: Number(raw.votingPower || 0),
    gasPrice: Number(raw.gasPrice || 0),
    commissionRate: Number(raw.commissionRate || 0) / 100,
    stakingPoolIotaBalance: Number(raw.stakingPoolIotaBalance || 0),
    nextEpochStake: Number(raw.nextEpochStake || 0),
  };
}

async function fetchFromRpc(): Promise<Validator[]> {
  const body = await callRpc(env.IOTA_RPC_METHOD);

  const validators =
    (body?.result?.activeValidators as RawValidator[] | undefined) ??
    (body?.result?.active_validators as RawValidator[] | undefined);
  if (!Array.isArray(validators)) {
    throw new Error('Invalid RPC response: missing activeValidators');
  }

  const normalized = validators.map(normalize);
  return Promise.all(
    normalized.map(async (validator) => {
      const parsed = parseMultiaddrHost(validator.netAddress) ?? parseMultiaddrHost(validator.p2pAddress);
      const projectHost = parseUrlHost(validator.projectUrl);
      const geo = await geolocateFromHosts([parsed?.host ?? null, projectHost], validator.id);
      return {
        ...validator,
        location: {
          ...geo.point,
          host: geo.host,
        },
      };
    }),
  );
}

async function callRpc(method: string) {
  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
    Accept: 'application/json',
  };

  if (env.IOTA_RPC_AUTH_HEADER && env.IOTA_RPC_AUTH_TOKEN) {
    headers[env.IOTA_RPC_AUTH_HEADER] = env.IOTA_RPC_AUTH_TOKEN;
  }

  const payload = {
    jsonrpc: '2.0',
    id: Date.now(),
    method,
    params: [],
  };

  const response = await fetch(env.IOTA_RPC_URL, {
    method: 'POST',
    headers,
    body: JSON.stringify(payload),
    signal: AbortSignal.timeout(10000),
    cache: 'no-store',
  });

  if (!response.ok) {
    throw new Error(`RPC HTTP ${response.status}`);
  }

  const body = await response.json();
  if (body.error) {
    throw new Error(`RPC ${body.error.code}: ${body.error.message}`);
  }

  return body;
}

async function fetchLatestCheckpoint() {
  const body = await callRpc(env.IOTA_CHECKPOINT_METHOD);
  const result = body?.result;

  if (typeof result === 'number' && Number.isFinite(result)) {
    return Math.floor(result);
  }

  if (typeof result === 'string' && /^\d+$/.test(result)) {
    return Number.parseInt(result, 10);
  }

  const seq = result?.sequenceNumber ?? result?.sequence_number ?? result?.checkpoint;
  if (typeof seq === 'number' && Number.isFinite(seq)) {
    return Math.floor(seq);
  }

  if (typeof seq === 'string' && /^\d+$/.test(seq)) {
    return Number.parseInt(seq, 10);
  }

  throw new Error('Invalid checkpoint RPC response shape');
}

function pushCheckpoint(checkpoint: number | null) {
  if (!Number.isFinite(checkpoint)) {
    return;
  }

  const value = Math.floor(checkpoint as number);
  const prev = state.checkpointHistory[state.checkpointHistory.length - 1];

  if (typeof prev !== 'number') {
    state.checkpointHistory = [value];
    return;
  }

  if (value > prev) {
    const delta = value - prev;
    if (delta <= env.CHECKPOINT_HISTORY_SIZE) {
      for (let i = 1; i <= delta; i += 1) {
        state.checkpointHistory.push(prev + i);
      }
    } else {
      state.checkpointHistory.push(value);
    }
  } else if (value === prev) {
    state.checkpointHistory.push(value);
  } else {
    state.checkpointHistory.push(value);
  }

  if (state.checkpointHistory.length > env.CHECKPOINT_HISTORY_SIZE) {
    state.checkpointHistory = state.checkpointHistory.slice(-env.CHECKPOINT_HISTORY_SIZE);
  }
}

export async function getLiveValidators(force = false): Promise<ValidatorsPayload> {
  const now = Date.now();
  const isFresh = now - lastRefreshMs < env.VALIDATORS_REFRESH_MS;

  if (!force && isFresh && state.validators.length > 0) {
    return state;
  }

  if (!refreshPromise) {
    refreshPromise = (async () => {
      try {
        const [validators, latestCheckpoint] = await Promise.all([
          fetchFromRpc(),
          fetchLatestCheckpoint().catch(() => null),
        ]);
        state.validators = validators;
        state.refreshMs = env.VALIDATORS_REFRESH_MS;
        state.updatedAt = new Date().toISOString();
        state.total = validators.length;
        state.latestCheckpoint = latestCheckpoint;
        pushCheckpoint(latestCheckpoint);
        state.error = null;
      } catch (error) {
        state.error = error instanceof Error ? error.message : 'Unknown refresh error';
      } finally {
        lastRefreshMs = Date.now();
      }

      return state;
    })().finally(() => {
      refreshPromise = null;
    });
  }

  return refreshPromise;
}

export function getRefreshMs() {
  return env.VALIDATORS_REFRESH_MS;
}

